const data = $json.body?.message_data || {};
const phone = `${$json.body?.phone_number}`;
const items = Array.isArray(data.items)
  ? data.items.map(i => `• ${i.quantity}x ${i.name} - R$ ${(i.price * i.quantity).toFixed(2)}`).join('\n')
  : 'Nenhum item';

let taxaEntrega = data.delivery_fee;
if (taxaEntrega === undefined || taxaEntrega === null || taxaEntrega === '' || isNaN(taxaEntrega)) {
  taxaEntrega = 'Grátis';
} else {
  taxaEntrega = parseFloat(taxaEntrega).toFixed(2);
}

const entrega = data.delivery_type === 'delivery'
  ? `Endereço: ${data.address}\nTaxa de Entrega: R$ ${taxaEntrega}`
  : 'Retirada no Local';

let financeiro = `Total: R$ ${parseFloat(data.total).toFixed(2)}`;
if (data.coupon_used && parseFloat(data.discount) > 0.01) {
  const taxaEntregaStr = data.delivery_type === 'delivery' ? (taxaEntrega === 'Grátis' ? '0.00' : taxaEntrega) : '0.00';
  financeiro = `Subtotal: R$ ${parseFloat(data.subtotal).toFixed(2)}\n`;
  if (data.delivery_type === 'delivery') {
    financeiro += `Taxa de Entrega: R$ ${taxaEntregaStr}\n`;
  }
  financeiro += `Desconto (Cupom: ${data.coupon_used}): -R$ ${parseFloat(data.discount).toFixed(2)}\n*Total Geral: R$ ${parseFloat(data.total).toFixed(2)}*`;
} else if (data.delivery_type === 'delivery' && parseFloat(data.delivery_fee) > 0) {
  financeiro = `Subtotal: R$ ${parseFloat(data.subtotal).toFixed(2)}\nTaxa de Entrega: R$ ${taxaEntrega}\n*Total: R$ ${parseFloat(data.total).toFixed(2)}*`;
}

const msg = `🍣 *Pedido enviado para C&R Sushi* 🍣\n\nPedido: ${data.order_number}\nStatus: ${data.status}\n\n*Detalhes do Pedido:*\n${items}\n\n*Detalhes da Entrega:*\n${entrega}\n\nPagamento: ${data.payment_method}\n\n${financeiro}\n\nNão responda esta mensagem caso tenha dúvida contate diretamente a *C&R Sushi* 👇\nhttps://wa.me/5573999743274?text=Olá%20tenho%20uma%20dúvida`;

return [{
  json: {
    phoneNumber: phone,
    message: msg
  }
}];

